static const uint8_t ICON_FRAME_WIDTH  = 32;
static const uint8_t ICON_FRAME_HEIGHT = 32;
static const uint8_t ICON_FRAME_BYTES  = 128;   // (32/8) * 32

#define ANIM_ICON(arr) \
  { (const uint8_t *)arr, (uint8_t)(sizeof(arr) / ICON_FRAME_BYTES), \
    ICON_FRAME_WIDTH, ICON_FRAME_HEIGHT }

const UiAnimIcon UI_MAIN_MENU_ANIM_ICONS[] = {
  ANIM_ICON(icon_cw_keyer),
  ANIM_ICON(icon_training),
  ANIM_ICON(icon_statistics),
  ANIM_ICON(icon_connectivity),
  ANIM_ICON(icon_profiles),
  ANIM_ICON(icon_settings),
  ANIM_ICON(icon_diagnostics),
  ANIM_ICON(icon_tools),
  ANIM_ICON(icon_games),
  ANIM_ICON(icon_help),
};
const uint8_t UI_MAIN_MENU_ANIM_ICON_COUNT =
  sizeof(UI_MAIN_MENU_ANIM_ICONS) / sizeof(UI_MAIN_MENU_ANIM_ICONS[0]);

const uint8_t *ui_anim_icon_getFrame(const UiAnimIcon &icon, uint16_t frameIndex) {
  if (icon.frameCount == 0) return icon.frames;
  uint8_t idx = (uint8_t)(frameIndex % icon.frameCount);
  return icon.frames + (size_t)idx * ICON_FRAME_BYTES;
}